                CREATE View [SSRS].[CountyCricketBoard_SeasonCurrLast_STD]  as    Select    Home_County_ID,    Home_County_Name,    Year_of_Fixture,    Sum([No Result])[No Result],     Sum(Abandoned  )Abandoned  ,   Sum(Cancelled  )Cancelled  ,   Sum(Conceded   )Conceded   ,   Sum(InProgress )InProgress ,   Sum(Win     )Win     ,   Sum(ShortSided )ShortSided     FROM   (  SELECT *    FROM [SSRS].[CountyCricketBoard_STD_2022] a    UNION      Select *   FROM    [SSRS].[CountyCricketBoard_2021Season]     )A     WHere MonthofFixture <= DATEPART(MONTH,GETDATE())-1     group by Home_County_ID,    Home_County_Name,    Year_of_Fixture        